     1ŌåÆ//! High-level statistical modeling API for Rust
     2ŌåÆ//!
     3ŌåÆ//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4ŌåÆ//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5ŌåÆ//! to provide a complete modeling workflow.
     6ŌåÆ
     7ŌåÆ#![forbid(unsafe_code)]
     8ŌåÆ#![warn(missing_docs)]
     9ŌåÆ
    10ŌåÆuse faer::{prelude::*, Mat};
    11ŌåÆ
    12ŌåÆ/// Statistical modeling errors
    13ŌåÆ#[derive(thiserror::Error, Debug)]
    14ŌåÆpub enum ModelError {
    15ŌåÆ    /// Linear algebra computation error
    16ŌåÆ    #[error("Linear algebra error: {0}")]
    17ŌåÆ    LinearAlgebra(String),
    18ŌåÆ    /// Invalid model specification
    19ŌåÆ    #[error("Invalid model: {0}")]
    20ŌåÆ    InvalidModel(String),
    21ŌåÆ}
    22ŌåÆ
    23ŌåÆ/// Common trait for all fitted models
    24ŌåÆpub trait Fit {
    25ŌåÆ    /// Get model coefficients
    26ŌåÆ    fn coefficients(&self) -> &[f64];
    27ŌåÆ
    28ŌåÆ    /// Get fitted values
    29ŌåÆ    fn fitted(&self) -> &[f64];
    30ŌåÆ
    31ŌåÆ    /// Get residuals
    32ŌåÆ    fn residuals(&self) -> &[f64];
    33ŌåÆ
    34ŌåÆ    /// Get model summary
    35ŌåÆ    fn summary(&self) -> ModelSummary;
    36ŌåÆ}
    37ŌåÆ
    38ŌåÆ/// Model summary information
    39ŌåÆ#[derive(Debug)]
    40ŌåÆpub struct ModelSummary {
    41ŌåÆ    /// Coefficient table
    42ŌåÆ    pub coefficients: Vec<CoefficientRow>,
    43ŌåÆ    /// R-squared (coefficient of determination)
    44ŌåÆ    pub r_squared: f64,
    45ŌåÆ    /// Adjusted R-squared
    46ŌåÆ    pub adj_r_squared: f64,
    47ŌåÆ    /// Residual standard error
    48ŌåÆ    pub residual_std_error: f64,
    49ŌåÆ    /// F-statistic for overall model significance
    50ŌåÆ    pub f_statistic: f64,
    51ŌåÆ    /// p-value for F-statistic
    52ŌåÆ    pub f_p_value: f64,
    53ŌåÆ    /// Degrees of freedom for model (number of predictors excluding intercept)
    54ŌåÆ    pub df_model: usize,
    55ŌåÆ    /// Degrees of freedom for residuals
    56ŌåÆ    pub df_residual: usize,
    57ŌåÆ}
    58ŌåÆ
    59ŌåÆ/// A row in the coefficient table
    60ŌåÆ#[derive(Debug)]
    61ŌåÆpub struct CoefficientRow {
    62ŌåÆ    /// Variable name
    63ŌåÆ    pub name: String,
    64ŌåÆ    /// Estimated coefficient
    65ŌåÆ    pub estimate: f64,
    66ŌåÆ    /// Standard error
    67ŌåÆ    pub std_error: f64,
    68ŌåÆ    /// t-statistic
    69ŌåÆ    pub t_value: f64,
    70ŌåÆ    /// p-value
    71ŌåÆ    pub p_value: f64,
    72ŌåÆ}
    73ŌåÆ
    74ŌåÆ/// Linear model fitting
    75ŌåÆpub struct Lm;
    76ŌåÆ
    77ŌåÆ/// Fitted linear model results
    78ŌåÆ#[derive(Debug)]
    79ŌåÆpub struct LmFit {
    80ŌåÆ    coefficients: Vec<f64>,
    81ŌåÆ    fitted_values: Vec<f64>,
    82ŌåÆ    residuals: Vec<f64>,
    83ŌåÆ    /// Number of observations
    84ŌåÆ    n_obs: usize,
    85ŌåÆ    /// Matrix rank (for rank-deficient matrices)
    86ŌåÆ    rank: usize,
    87ŌåÆ    /// Design matrix for statistical inference (stored for covariance calculation)
    88ŌåÆ    x_matrix: Mat<f64>,
    89ŌåÆ}
    90ŌåÆ
    91ŌåÆimpl Lm {
    92ŌåÆ    /// Fit a linear model using QR decomposition with column pivoting
    93ŌåÆ    ///
    94ŌåÆ    /// This implementation uses faer's column-pivoted QR decomposition to handle
    95ŌåÆ    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    96ŌåÆ    pub fn fit(
    97ŌåÆ        x_data: &[f64],
    98ŌåÆ        y_data: &[f64],
    99ŌåÆ        n_rows: usize,
   100ŌåÆ        n_cols: usize,
   101ŌåÆ    ) -> Result<LmFit, ModelError> {
   102ŌåÆ        if x_data.len() != n_rows * n_cols {
   103ŌåÆ            return Err(ModelError::InvalidModel(
   104ŌåÆ                "Design matrix dimensions don't match data".to_string(),
   105ŌåÆ            ));
   106ŌåÆ        }
   107ŌåÆ
   108ŌåÆ        if y_data.len() != n_rows {
   109ŌåÆ            return Err(ModelError::InvalidModel(
   110ŌåÆ                "Response vector length doesn't match number of observations".to_string(),
   111ŌåÆ            ));
   112ŌåÆ        }
   113ŌåÆ
   114ŌåÆ        // Create faer matrices from input data
   115ŌåÆ        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   116ŌåÆ        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   117ŌåÆ
   118ŌåÆ        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   119ŌåÆ        let qr = x_mat.col_piv_qr();
   120ŌåÆ
   121ŌåÆ        // Calculate rank from R matrix diagonal elements
   122ŌåÆ        let r_matrix = qr.R();
   123ŌåÆ        let tolerance = 1e-12;
   124ŌåÆ        let mut rank = 0;
   125ŌåÆ        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   126ŌåÆ            if r_matrix[(i, i)].abs() > tolerance {
   127ŌåÆ                rank += 1;
   128ŌåÆ            }
   129ŌåÆ        }
   130ŌåÆ
   131ŌåÆ        // Handle rank-deficient matrices by checking for numerical instability
   132ŌåÆ        let coefficients_mat = qr.solve_lstsq(&y_mat);
   133ŌåÆ
   134ŌåÆ        // Check for numerical instability and apply correction if needed
   135ŌåÆ        let has_instability =
   136ŌåÆ            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   137ŌåÆ
   138ŌåÆ        let final_coefficients_mat = if has_instability {
   139ŌåÆ            // For rank-deficient case, set coefficients for columns beyond rank to zero
   140ŌåÆ            let mut corrected_coefs = Vec::new();
   141ŌåÆ            for i in 0..coefficients_mat.nrows() {
   142ŌåÆ                let coef = coefficients_mat[(i, 0)];
   143ŌåÆ                if coef.abs() > 1e10 {
   144ŌåÆ                    corrected_coefs.push(0.0);
   145ŌåÆ                } else {
   146ŌåÆ                    corrected_coefs.push(coef);
   147ŌåÆ                }
   148ŌåÆ            }
   149ŌåÆ            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   150ŌåÆ        } else {
   151ŌåÆ            coefficients_mat
   152ŌåÆ        };
   153ŌåÆ
   154ŌåÆ        // Calculate fitted values: ┼Ę = X * ╬▓ (using corrected coefficients)
   155ŌåÆ        let fitted_mat = &x_mat * &final_coefficients_mat;
   156ŌåÆ
   157ŌåÆ        // Calculate residuals: e = y - ┼Ę
   158ŌåÆ        let residuals_mat = &y_mat - &fitted_mat;
   159ŌåÆ
   160ŌåÆ        // Extract results to plain Vec<f64> for API
   161ŌåÆ        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   162ŌåÆ            .map(|i| final_coefficients_mat[(i, 0)])
   163ŌåÆ            .collect();
   164ŌåÆ
   165ŌåÆ        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   166ŌåÆ            .map(|i| fitted_mat[(i, 0)])
   167ŌåÆ            .collect();
   168ŌåÆ
   169ŌåÆ        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   170ŌåÆ            .map(|i| residuals_mat[(i, 0)])
   171ŌåÆ            .collect();
   172ŌåÆ
   173ŌåÆ        // rank is already computed above using qr.rank()
   174ŌåÆ
   175ŌåÆ        Ok(LmFit {
   176ŌåÆ            coefficients,
   177ŌåÆ            fitted_values,
   178ŌåÆ            residuals,
   179ŌåÆ            n_obs: n_rows,
   180ŌåÆ            rank,
   181ŌåÆ            x_matrix: x_mat,
   182ŌåÆ        })
   183ŌåÆ    }
   184ŌåÆ}
   185ŌåÆ
   186ŌåÆimpl LmFit {
   187ŌåÆ    /// Get the number of observations used in the model
   188ŌåÆ    pub fn n_obs(&self) -> usize {
   189ŌåÆ        self.n_obs
   190ŌåÆ    }
   191ŌåÆ
   192ŌåÆ    /// Get the rank of the design matrix (number of linearly independent columns)
   193ŌåÆ    pub fn rank(&self) -> usize {
   194ŌåÆ        self.rank
   195ŌåÆ    }
   196ŌåÆ
   197ŌåÆ    /// Get degrees of freedom for error (n_obs - rank)
   198ŌåÆ    pub fn df_resid(&self) -> usize {
   199ŌåÆ        self.n_obs.saturating_sub(self.rank)
   200ŌåÆ    }
   201ŌåÆ}
   202ŌåÆ
   203ŌåÆimpl Fit for LmFit {
   204ŌåÆ    fn coefficients(&self) -> &[f64] {
   205ŌåÆ        &self.coefficients
   206ŌåÆ    }
   207ŌåÆ
   208ŌåÆ    fn fitted(&self) -> &[f64] {
   209ŌåÆ        &self.fitted_values
   210ŌåÆ    }
   211ŌåÆ
   212ŌåÆ    fn residuals(&self) -> &[f64] {
   213ŌåÆ        &self.residuals
   214ŌåÆ    }
   215ŌåÆ
   216ŌåÆ    fn summary(&self) -> ModelSummary {
   217ŌåÆ        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   218ŌåÆ
   219ŌåÆ        // Calculate residual standard error: s┬▓ = RSS / (n - p)
   220ŌåÆ        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   221ŌåÆ        let df_resid = self.df_resid() as f64;
   222ŌåÆ        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   223ŌåÆ        let residual_std_error = mse.sqrt();
   224ŌåÆ
   225ŌåÆ        // Calculate Total Sum of Squares (TSS) and R-squared
   226ŌåÆ        let y_mean: f64 = self
   227ŌåÆ            .fitted_values
   228ŌåÆ            .iter()
   229ŌåÆ            .zip(self.residuals.iter())
   230ŌåÆ            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
   231ŌåÆ            .sum::<f64>()
   232ŌåÆ            / self.n_obs as f64;
   233ŌåÆ
   234ŌåÆ        let tss: f64 = self
   235ŌåÆ            .fitted_values
   236ŌåÆ            .iter()
   237ŌåÆ            .zip(self.residuals.iter())
   238ŌåÆ            .map(|(fitted, resid)| {
   239ŌåÆ                let y = fitted + resid;
   240ŌåÆ                (y - y_mean).powi(2)
   241ŌåÆ            })
   242ŌåÆ            .sum();
   243ŌåÆ
   244ŌåÆ        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   245ŌåÆ
   246ŌåÆ        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
   247ŌåÆ        let n = self.n_obs as f64;
   248ŌåÆ        let p = self.rank as f64;
   249ŌåÆ        let adj_r_squared = if n > 1.0 && p > 0.0 {
   250ŌåÆ            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
   251ŌåÆ        } else {
   252ŌåÆ            r_squared
   253ŌåÆ        };
   254ŌåÆ
   255ŌåÆ        // F-statistic for overall model significance
   256ŌåÆ        // RSS for null model (intercept only) equals TSS
   257ŌåÆ        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
   258ŌåÆ        let f_statistic = if df_model > 0 {
   259ŌåÆ            model_f_statistic(rss, tss, df_model, self.df_resid())
   260ŌåÆ        } else {
   261ŌåÆ            0.0
   262ŌåÆ        };
   263ŌåÆ
   264ŌåÆ        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
   265ŌåÆ            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
   266ŌåÆ        } else {
   267ŌåÆ            1.0
   268ŌåÆ        };
   269ŌåÆ
   270ŌåÆ        // Calculate variance-covariance matrix: Žā┬▓ * (X'X)^(-1)
   271ŌåÆ        // Compute X'X
   272ŌåÆ        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   273ŌåÆ
   274ŌåÆ        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
   275ŌåÆ        let qr = xtx.col_piv_qr();
   276ŌåÆ        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   277ŌåÆ        let xtx_inv = qr.solve(&identity);
   278ŌåÆ
   279ŌåÆ        // Standard errors are sqrt of diagonal elements of Žā┬▓ * (X'X)^(-1)
   280ŌåÆ        let std_errors: Vec<f64> = (0..self.coefficients.len())
   281ŌåÆ            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   282ŌåÆ            .collect();
   283ŌåÆ
   284ŌåÆ        let t_stats = t_statistics(&self.coefficients, &std_errors);
   285ŌåÆ        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   286ŌåÆ
   287ŌåÆ        let mut coefficient_rows = Vec::new();
   288ŌåÆ        for (i, &coef) in self.coefficients.iter().enumerate() {
   289ŌåÆ            let name = if i == 0 {
   290ŌåÆ                "Intercept".to_string()
   291ŌåÆ            } else {
   292ŌåÆ                format!("X{}", i)
   293ŌåÆ            };
   294ŌåÆ
   295ŌåÆ            coefficient_rows.push(CoefficientRow {
   296ŌåÆ                name,
   297ŌåÆ                estimate: coef,
   298ŌåÆ                std_error: std_errors[i],
   299ŌåÆ                t_value: t_stats[i],
   300ŌåÆ                p_value: p_values[i],
   301ŌåÆ            });
   302ŌåÆ        }
   303ŌåÆ
   304ŌåÆ        ModelSummary {
   305ŌåÆ            coefficients: coefficient_rows,
   306ŌåÆ            r_squared,
   307ŌåÆ            adj_r_squared,
   308ŌåÆ            residual_std_error,
   309ŌåÆ            f_statistic,
   310ŌåÆ            f_p_value,
   311ŌåÆ            df_model,
   312ŌåÆ            df_residual: self.df_resid(),
   313ŌåÆ        }
   314ŌåÆ    }
   315ŌåÆ}
